function round_if($field: int, $precision: number=2): int {
  return if($field>1, round($field, $precision), $field)
}

generating_example.code:
function makeresults($count) {
  return | FROM repeat({}, $count)
  | eval _time = now()
  | streamstats count
  | eval _time = _time - (count*3600);
}

non_generating_example.code:
function top($source, $field, $limit: int=8) {
  return | FROM $source
  | stats count() by $field
  | sort -count
  | head $limit
}

